const body = $input.first().json.body || $input.first().json;
return [{
  json: {
    jobId: body.jobId,
    campaignId: body.campaignId,
    keyword: body.keyword || body.keywords?.[0] || '',
    location: body.location || '',
    maxResults: parseInt(body.maxResults) || 20
  }
}];

const page1 = $input.first().json;
const inputData = $('Parse Input').first().json;
const results = page1.results || [];
const nextToken = page1.next_page_token || null;

return [{
  json: {
    ...inputData,
    results,
    nextPageToken: nextToken,
    totalFound: results.length
  }
}];

const page2 = $input.first().json;
const prev = $('Collect Page 1 Results').first().json;
const newResults = page2.results || [];
const allResults = [...prev.results, ...newResults];

return [{
  json: {
    ...prev,
    results: allResults,
    nextPageToken: page2.next_page_token || null,
    totalFound: allResults.length
  }
}];

const data = $input.first().json;
const maxResults = data.maxResults || 20;
const limited = data.results.slice(0, maxResults);

return limited.map(place => ({
  json: {
    jobId: data.jobId,
    campaignId: data.campaignId,
    keyword: data.keyword,
    location: data.location,
    placeId: place.place_id,
    companyName: place.name,
    address: place.formatted_address || '',
    rating: place.rating || null,
    totalRatings: place.user_ratings_total || 0,
    businessStatus: place.business_status || 'OPERATIONAL',
    types: (place.types || []).join(',')
  }
}));

const detail = $input.first().json.result || {};
const prev = $('Split & Limit Places').first().json;

const website = detail.website || null;
const phone = detail.formatted_phone_number || detail.international_phone_number || null;

return [{
  json: {
    ...prev,
    website,
    phone
  }
}];

function toStr(x) {
  if (!x) return '';
  if (typeof x === 'string') return x;
  if (x.data && typeof x.data === 'string') return x.data;
  if (x.body && typeof x.body === 'string') return x.body;
  return JSON.stringify(x);
}

const homeHtml = toStr($('Crawl Homepage').first()?.json);
const contactHtml = toStr($('Crawl /contact').first()?.json);
const combined = homeHtml + '\n' + contactHtml;

const placeData = $('Merge Place Details').first().json;

// Decode obfuscations
let html = combined
  .replace(/[\u200B-\u200D\u2060\uFEFF]/g, '')
  .replace(/\s*\[at\]\s*|\s*\(at\)\s*|\s+at\s+/gi, '@')
  .replace(/\s*\[dot\]\s*|\s*\(dot\)\s*|\s+dot\s+/gi, '.')
  .replace(/&#x40;|&#64;|&commat;/gi, '@')
  .replace(/&#46;|&period;/gi, '.')
  .replace(/\s+@\s+/g, '@')
  .replace(/\s+\.\s+/g, '.');

// Extract emails
const mailtos = (html.match(/mailto:([a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,24})/gi) || [])
  .map(m => m.replace(/^mailto:/i, ''));
const plain = (html.match(/[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,24}/gi) || []);
let emails = Array.from(new Set([...mailtos, ...plain].map(e => e.toLowerCase().trim())))
  .map(e => e.replace(/[),;:'"]+$/g, ''));

// Filter
const assetTLD = new Set(['png','jpg','jpeg','gif','svg','webp','ico','pdf','css','js','mp4']);
const denyDomains = /(sentry\.io|cloudflare\.com|w3\.org|example\.com|test\.com|localhost)/i;
const denyPlaceholder = /^(user|username|name|test|demo)@/i;

emails = emails.filter(e => {
  const parts = e.split('@');
  if (parts.length !== 2) return false;
  const [local, domain] = parts;
  const tld = domain.split('.').pop();
  if (assetTLD.has(tld)) return false;
  if (denyDomains.test(domain)) return false;
  if (denyPlaceholder.test(local)) return false;
  if (local.length < 2 || domain.length < 4) return false;
  return true;
});

// Pick best email: info@ > contact@ > sales@ > first
const priority = ['info@', 'contact@', 'sale', 'hello@', 'admin@'];
let bestEmail = null;
for (const p of priority) {
  const found = emails.find(e => e.startsWith(p));
  if (found) { bestEmail = found; break; }
}
if (!bestEmail) bestEmail = emails[0] || null;

return [{
  json: {
    ...placeData,
    email: bestEmail,
    allEmails: emails.slice(0, 5)
  }
}];

// No website — still save lead without email
const d = $input.first().json;
return [{ json: { ...d, email: null, allEmails: [] } }];
